module top_module (
    input w,
    input r,
    input v,
    input j,
    output reg valid_output
);
    always @(*) begin
        case ({w, r, v, j})
            4'b0111: valid_output = 1'b1;
            4'b1011: valid_output = 1'b1;
            4'b0011: valid_output = 1'b0;
            4'b1111: valid_output = 1'b1;
            4'b1101: valid_output = 1'b1;
            4'b1010: valid_output = 1'b1;
            4'b0001: valid_output = 1'b1;
            4'b0110: valid_output = 1'b1;
            4'b0101: valid_output = 1'b0;
            4'b1001: valid_output = 1'b0;
            4'b1100: valid_output = 1'b1;
            4'b1000: valid_output = 1'b0;
            4'b0000: valid_output = 1'b0;
            4'b0100: valid_output = 1'b0;
            4'b1110: valid_output = 1'b1;
            4'b0010: valid_output = 1'b1;
        endcase
    end
endmodule
